/**
 * SMS notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'sms' channel.
 * Validates phone numbers, formats messages for SMS length constraints,
 * and delivers via a pluggable transport layer. Uses an in-memory
 * transport by default for testing.
 *
 * NOTE: User preferences currently only support email channel preferences.
 * The preferences model (src/models/user-preferences.ts) needs to be
 * extended to support SMS preferences (enabled, subscribed categories, etc.)
 * before SMS preference checking can be wired into NotificationService.
 * See COORDINATION.md for details.
 */

import { Logger } from '../utils/logger.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';

/** Maximum length for an SMS message body. */
export const SMS_MAX_LENGTH = 160;

/** Record of a sent SMS, including delivery metadata. */
export interface SentSMS {
  to: string;
  body: string;
  sentAt: Date;
  notificationType: string;
  messageId: string;
}

/**
 * Transport interface for pluggable SMS delivery.
 * Implement this to integrate with real SMS providers (e.g., Twilio, SNS).
 */
export interface SMSTransport {
  sendSMS(to: string, body: string): Promise<{ messageId: string }>;
}

/**
 * In-memory transport that stores SMS messages instead of sending them.
 * Used by default for testing and development.
 */
export class InMemorySMSTransport implements SMSTransport {
  private counter = 0;

  async sendSMS(to: string, body: string): Promise<{ messageId: string }> {
    this.counter++;
    return { messageId: `sms-${String(this.counter).padStart(6, '0')}` };
  }
}

/**
 * Validate that a string looks like a phone number.
 * Accepts E.164 format (+1234567890) and common formats with digits,
 * spaces, dashes, and parentheses. Must contain at least 7 digits.
 */
function isValidPhoneNumber(phone: string): boolean {
  const digitsOnly = phone.replace(/[\s\-\(\)\.]/g, '');
  if (!/^\+?\d+$/.test(digitsOnly)) {
    return false;
  }
  const digitCount = digitsOnly.replace(/\D/g, '').length;
  return digitCount >= 7 && digitCount <= 15;
}

/**
 * Normalize a phone number to a clean format.
 * Strips whitespace and common formatting characters.
 */
function normalizePhoneNumber(phone: string): string {
  return phone.replace(/[\s\-\(\)\.]/g, '');
}

export class SMSAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SMSAdapter');
  private sentMessages: SentSMS[] = [];
  private transport: SMSTransport;

  constructor(transport?: SMSTransport) {
    this.transport = transport ?? new InMemorySMSTransport();
  }

  /**
   * Format a notification payload into an SMS message body.
   * Truncates to SMS_MAX_LENGTH if needed.
   */
  formatMessage(payload: NotificationPayload): string {
    const message = `${payload.subject}: ${payload.body}`;
    if (message.length <= SMS_MAX_LENGTH) {
      return message;
    }
    return message.substring(0, SMS_MAX_LENGTH - 3) + '...';
  }

  /**
   * Resolve and validate the recipient phone number.
   * Returns the normalized phone number or null if invalid.
   */
  resolveRecipient(payload: NotificationPayload): string | null {
    const phone = payload.recipient.trim();

    if (!phone) {
      this.logger.warn('Empty phone number');
      return null;
    }

    if (!isValidPhoneNumber(phone)) {
      this.logger.warn(`Invalid phone number: ${phone}`);
      return null;
    }

    return normalizePhoneNumber(phone);
  }

  /**
   * Send an SMS notification.
   * Validates the recipient, formats the message, and delivers via transport.
   * Never throws — returns { success: false } on failure.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const resolvedRecipient = this.resolveRecipient(payload);

      if (!resolvedRecipient) {
        return {
          success: false,
          channel: 'sms',
          message: `Invalid phone number: ${payload.recipient}`,
        };
      }

      const body = this.formatMessage(payload);

      this.logger.info(`Sending SMS to ${resolvedRecipient}: ${payload.subject}`);

      const { messageId } = await this.transport.sendSMS(resolvedRecipient, body);

      const record: SentSMS = {
        to: resolvedRecipient,
        body,
        sentAt: new Date(),
        notificationType: payload.notificationType,
        messageId,
      };

      this.sentMessages.push(record);

      return {
        success: true,
        channel: 'sms',
        message: `SMS delivered to ${resolvedRecipient} (${messageId})`,
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);
      return {
        success: false,
        channel: 'sms',
        message,
      };
    }
  }

  /**
   * Get all SMS messages sent through this adapter. Useful for testing.
   */
  getSentMessages(): SentSMS[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent SMS history. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

