import { describe, it, expect, beforeEach } from 'vitest';
import {
  SMSAdapter,
  InMemorySMSTransport,
  SMS_MAX_LENGTH,
} from '../../src/adapters/sms.adapter.js';
import type { SMSTransport } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    channel: 'sms',
    notificationType: 'order-confirmation',
    recipient: '+15551234567',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    metadata: { orderId: 'order-1', userId: 'user-1' },
    ...overrides,
  };
}

describe('SMSAdapter', () => {
  let adapter: SMSAdapter;

  beforeEach(() => {
    adapter = new SMSAdapter();
  });

  describe('resolveRecipient', () => {
    it('should accept a valid E.164 phone number', () => {
      const payload = makePayload({ recipient: '+15551234567' });
      expect(adapter.resolveRecipient(payload)).toBe('+15551234567');
    });

    it('should accept a phone number without plus prefix', () => {
      const payload = makePayload({ recipient: '15551234567' });
      expect(adapter.resolveRecipient(payload)).toBe('15551234567');
    });

    it('should strip formatting characters', () => {
      const payload = makePayload({ recipient: '+1 (555) 123-4567' });
      expect(adapter.resolveRecipient(payload)).toBe('+15551234567');
    });

    it('should trim whitespace', () => {
      const payload = makePayload({ recipient: '  +15551234567  ' });
      expect(adapter.resolveRecipient(payload)).toBe('+15551234567');
    });

    it('should return null for empty phone number', () => {
      const payload = makePayload({ recipient: '' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });

    it('should return null for invalid phone number with letters', () => {
      const payload = makePayload({ recipient: 'not-a-phone' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });

    it('should return null for too-short phone number', () => {
      const payload = makePayload({ recipient: '12345' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });

    it('should return null for too-long phone number', () => {
      const payload = makePayload({ recipient: '+1234567890123456' });
      expect(adapter.resolveRecipient(payload)).toBeNull();
    });
  });

  describe('formatMessage', () => {
    it('should combine subject and body', () => {
      const payload = makePayload({ subject: 'Alert', body: 'Something happened' });
      expect(adapter.formatMessage(payload)).toBe('Alert: Something happened');
    });

    it('should truncate messages exceeding SMS_MAX_LENGTH', () => {
      const longBody = 'A'.repeat(200);
      const payload = makePayload({ body: longBody });
      const formatted = adapter.formatMessage(payload);

      expect(formatted.length).toBe(SMS_MAX_LENGTH);
      expect(formatted.endsWith('...')).toBe(true);
    });

    it('should not truncate messages within SMS_MAX_LENGTH', () => {
      const payload = makePayload({ subject: 'Hi', body: 'Short' });
      const formatted = adapter.formatMessage(payload);

      expect(formatted).toBe('Hi: Short');
      expect(formatted.length).toBeLessThanOrEqual(SMS_MAX_LENGTH);
    });
  });

  describe('send', () => {
    it('should successfully send a valid SMS', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.message).toContain('+15551234567');
    });

    it('should store sent SMS with message details', async () => {
      const payload = makePayload();
      await adapter.send(payload);

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.body).toBe('Order Confirmation: Your order has been placed.');
      expect(sent[0]?.notificationType).toBe('order-confirmation');
      expect(sent[0]?.messageId).toMatch(/^sms-/);
    });

    it('should return failure for invalid phone number', async () => {
      const payload = makePayload({ recipient: 'not-valid' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.channel).toBe('sms');
      expect(result.message).toContain('Invalid phone number');
    });

    it('should not store SMS on validation failure', async () => {
      const payload = makePayload({ recipient: 'bad-number' });
      await adapter.send(payload);

      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should return failure when transport throws', async () => {
      const failingTransport: SMSTransport = {
        async sendSMS(): Promise<{ messageId: string }> {
          throw new Error('Service unavailable');
        },
      };

      const failAdapter = new SMSAdapter(failingTransport);
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('sms');
      expect(result.message).toBe('Service unavailable');
    });

    it('should not store SMS when transport throws', async () => {
      const failingTransport: SMSTransport = {
        async sendSMS(): Promise<{ messageId: string }> {
          throw new Error('fail');
        },
      };

      const failAdapter = new SMSAdapter(failingTransport);
      await failAdapter.send(makePayload());

      expect(failAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should handle non-Error thrown by transport', async () => {
      const failingTransport: SMSTransport = {
        async sendSMS(): Promise<{ messageId: string }> {
          throw 'string error';
        },
      };

      const failAdapter = new SMSAdapter(failingTransport);
      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.message).toBe('Unknown transport error');
    });

    it('should assign unique message IDs to each SMS', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: '+15559876543' }));

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.messageId).not.toBe(sent[1]?.messageId);
    });
  });

  describe('custom transport', () => {
    it('should use injected transport', async () => {
      const calls: { to: string; body: string }[] = [];
      const customTransport: SMSTransport = {
        async sendSMS(to: string, body: string) {
          calls.push({ to, body });
          return { messageId: 'custom-001' };
        },
      };

      const customAdapter = new SMSAdapter(customTransport);
      await customAdapter.send(makePayload());

      expect(calls).toHaveLength(1);
      expect(calls[0]?.to).toBe('+15551234567');

      const sent = customAdapter.getSentMessages();
      expect(sent[0]?.messageId).toBe('custom-001');
    });
  });

  describe('getSentMessages and clearSentMessages', () => {
    it('should return a copy of sent messages', async () => {
      await adapter.send(makePayload());
      const msgs1 = adapter.getSentMessages();
      const msgs2 = adapter.getSentMessages();
      expect(msgs1).toEqual(msgs2);
      expect(msgs1).not.toBe(msgs2);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });
});

describe('InMemorySMSTransport', () => {
  it('should return sequential message IDs', async () => {
    const transport = new InMemorySMSTransport();
    const r1 = await transport.sendSMS('+15551234567', 'Hello');
    const r2 = await transport.sendSMS('+15559876543', 'World');

    expect(r1.messageId).toBe('sms-000001');
    expect(r2.messageId).toBe('sms-000002');
  });
});

